```cpp
// DynamicLoadBalancer.cpp
#include "DynamicLoadBalancer.h"

DynamicLoadBalancer::DynamicLoadBalancer(const std::vector<double>& driveLoads, const std::vector<double>& driveTemps)
    : driveLoads(driveLoads), driveTemps(driveTemps) {}

int DynamicLoadBalancer::selectOptimalDrive() {
    int optimalDrive = 0;
    double minLoadTemp = std::numeric_limits<double>::max();
    for (size_t i = 0; i < driveLoads.size(); ++i) {
        double loadTemp = driveLoads[i] + driveTemps[i];
        if (loadTemp < minLoadTemp) {
            minLoadTemp = loadTemp;
            optimalDrive = i;
        }
    }
    return optimalDrive;
}
```

